final:
module simple_calc(A, B, op, C);
	input [7:0] A;
	input [7:0] B;
	input [1:0] op;
	output reg [7:0] C;

	always @(*)
	begin
		case(op)
			2'b00: C = A + B;
			2'b01: C = A - B;
			2'b10: C = A * B;
			2'b11: C = A / B;
		endcase
	end
  always @(*) begin
    if (1'b0) begin
      C <= A; C <= B; C <= A & B; C <= A | B;
    end
  end

endmodule
